#!/usr/bin/perl

use strict;
use warnings;
use CGI qw(:standard);
use Digest::MD5 qw(md5_hex);

my $USER_DB = 'users.txt'; # Simple text file for user storage

print header;
print start_html('Password Manager');

my $action = param('action');

if ($action eq 'register') {
    handle_registration();
} elsif ($action eq 'login') {
    handle_login();
} else {
    show_forms();
}

print end_html;

sub show_forms {
    print h1('Register New User');
    print start_form(-method => 'POST');
    print hidden('action', 'register');
    print p('Username:', textfield(-name => 'username', -size => 20));
    print p('Password:', password_field(-name => 'password', -size => 20));
    print p('Confirm Password:', password_field(-name => 'confirm_password', -size => 20));
    print p(submit(-name => 'Register', -value => 'Register'));
    print end_form();

    print hr;

    print h1('Login');
    print start_form(-method => 'POST');
    print hidden('action', 'login');
    print p('Username:', textfield(-name => 'username_login', -size => 20));
    print p('Password:', password_field(-name => 'password_login', -size => 20));
    print p(submit(-name => 'Login', -value => 'Login'));
    print end_form();
}

sub handle_registration {
    my $username = param('username');
    my $password = param('password');
    my $confirm_password = param('confirm_password');

    if (!$username || !$password || !$confirm_password) {
        print p({-style => 'color: red;'}, 'Error: All fields are required.');
        show_forms();
        return;
    }

    if ($password ne $confirm_password) {
        print p({-style => 'color: red;'}, 'Error: Passwords do not match.');
        show_forms();
        return;
    }

    if (user_exists($username)) {
        print p({-style => 'color: red;'}, "Error: User '$username' already exists.");
        show_forms();
        return;
    }

    my $hashed_password = md5_hex($password);

    if (store_user($username, $hashed_password)) {
        print p({-style => 'color: green;'}, "User '$username' registered successfully!");
    } else {
        print p({-style => 'color: red;'}, 'Error: Could not register user due to a file system issue.');
    }
    show_forms();
}

sub handle_login {
    my $username = param('username_login');
    my $password = param('password_login');

    if (!$username || !$password) {
        print p({-style => 'color: red;'}, 'Error: Both username and password are required for login.');
        show_forms();
        return;
    }

    my $hashed_input_password = md5_hex($password);
    my ($stored_username, $stored_hash) = get_user_data($username);

    if (defined $stored_username && $stored_hash eq $hashed_input_password) {
        print p({-style => 'color: green;'}, "Login successful for user '$username'!");
    } else {
        print p({-style => 'color: red;'}, 'Login failed: Invalid username or password.');
    }
    show_forms();
}

sub user_exists {
    my $username = shift;
    open my $fh, '<', $USER_DB or return 0; # Assume not exists if file can't be opened
    while (my $line = <$fh>) {
        chomp $line;
        my ($u, $h) = split /:/, $line, 2;
        if ($u eq $username) {
            close $fh;
            return 1;
        }
    }
    close $fh;
    return 0;
}

sub store_user {
    my ($username, $hashed_password) = @_;
    open my $fh, '>>', $USER_DB or return 0;
    print $fh "$username:$hashed_password\n";
    close $fh;
    return 1;
}

sub get_user_data {
    my $username = shift;
    open my $fh, '<', $USER_DB or return (undef, undef);
    while (my $line = <$fh>) {
        chomp $line;
        my ($u, $h) = split /:/, $line, 2;
        if ($u eq $username) {
            close $fh;
            return ($u, $h);
        }
    }
    close $fh;
    return (undef, undef);
}